import React, { useRef, useState } from 'react'
import {
  DialogOverlay,
  Button,
  useContainerWidth,
  Separator,
  Row,
  DialogOverlayFooter,
  DialogOverlayActions,
  Paragraph,
  useStatusOverlay,
  H6,
  Subheading,
} from '@fs/zion-ui'
import { useTranslation } from 'react-i18next'

import ZionForm, { useZionForm, FormRadioGroup, FormRadio } from '@fs/zion-form'
import { useUserProfile } from '@fs/zion-user'
import { setPreference } from '@fs/zion-preferences'
import { trackLink } from '@fs/zion-analytics'
import ProfilePreview from './ProfilePreview'
import { profileInterrupterPrefKey } from './profileOptInHelper'

/**
 * ChatProfileInterrupter is a dialog overlay prompting users to update profile permissions.
 * @returns {JSX.Element}
 * @constructor
 * @param {Object} overlay overlay object
 * @param {String} mainMessage message displayed in form
 */

export default function ChatProfileInterrupter({ overlay, mainMessage }) {
  const [t] = useTranslation()
  const atWidth = useContainerWidth()
  const formRef = useRef()
  const { userProfile, userProfileLoading, setOptInStatus } = useUserProfile()
  const showStatusOverlay = useStatusOverlay()
  const focusRef = useRef()

  const [submitLoading, setSubmitLoading] = useState(false)

  const optInText = t(
    'chat.profile-interrupter-form-opt-in.button',
    'Include my profile information in directory search results.'
  )
  const optInHelpText = t(
    'chat.profile-interrupter-form-opt-in.help-text',
    'Family, friends, and others on FamilySearch will be able to find and collaborate with me.'
  )
  const optOutText = t(
    'chat.profile-interrupter-form-opt-out.button',
    "No, I don't want to appear in directory search results."
  )

  const dismissableSuccessProps = {
    message: t('chat.profile-interrupter-opt-in-success.message', `We'll include you in directory search results.`),
    dismissable: true,
    type: 'success',
    actionLabel: t('chat.profile-interrupter-update.button', `Update Profile`),
    actionCallback: () => {
      window.location.assign('https://www.familysearch.org/identity/settings/profile')
    },
  }

  const postProfileData = async (formData) => {
    if (!formData) {
      return
    }
    const optedIn = formData.directoryChoice === 'optIn'
    if (formData.directoryChoice === 'optOut') {
      dismissableSuccessProps.message = t(
        'chat.profile-interrupter-opt-out-success.message',
        `We'll leave you out of directory search results.`
      )
    }
    const response = await setOptInStatus(optedIn)
    if (response) {
      showStatusOverlay(dismissableSuccessProps)
    }
  }

  const methods = useZionForm({
    mode: 'all',
    defaultValues: { directoryChoice: 'optIn' },
    reValidateMode: 'onChange',
  })

  const handleFormSubmit = async (formData) => {
    const timeNow = new Date()
    setSubmitLoading(true)
    try {
      await postProfileData(formData)
      setSubmitLoading(false)
      await setPreference(profileInterrupterPrefKey, { interaction: 'UPDATED', time: timeNow.getTime() })
      trackLink(null, null, 'click_action', `profile-interrupter:dismiss`)
      overlay.close()
    } catch {
      showStatusOverlay({
        message: t(
          'chat.profile-interruptor-opt-in-error-message',
          'Your selection could not be saved. Please try again.'
        ),
        type: 'warning',
        dismissable: true,
      })
    }
  }

  const handleLater = async () => {
    const timeNow = new Date()
    setPreference(profileInterrupterPrefKey, { interaction: 'LATER', time: timeNow.getTime() })
    trackLink(null, null, 'click_action', `profile-interrupter:later`)
    overlay.close()
  }

  return (
    <DialogOverlay
      as={ZionForm}
      methods={methods}
      onSubmit={handleFormSubmit}
      ref={formRef}
      focusRef={focusRef}
      {...overlay}
      title={t('chat.profile-interrupter.heading', 'Join FamilySearch Chat')}
      subtitle={t('chat.profile-interrupter.subheading', 'Connect with family and friends on FamilySearch')}
      closeOnClickAway={false}
    >
      <Paragraph>{mainMessage}</Paragraph>
      {userProfile && <ProfilePreview userProfile={userProfile} />}
      <Separator size="sm" />
      <H6>
        {t('chat.profile-interrupter-subheader.heading', 'Choose Your Directory Preference')}
        <Subheading>
          {t('chat.profile-interrupter-subheader.subheading', 'This can be changed later in Settings.')}
        </Subheading>
      </H6>
      <Separator size={atWidth({ sm: 'xs', md: 'sm' })} />
      <FormRadioGroup orientation="horizontal">
        <FormRadio
          label={
            <>
              {optInText}
              <Paragraph size="xs">{optInHelpText}</Paragraph>
            </>
          }
          value="optIn"
          name="directoryChoice"
          wrapLabel
        />
        <FormRadio label={optOutText} value="optOut" name="directoryChoice" wrapLabel />
      </FormRadioGroup>

      <DialogOverlayFooter>
        <DialogOverlayActions>
          <Row alignX="end" alignY="middle">
            <Button onClick={handleLater} disabled={userProfileLoading}>
              {t('chat.profile-interrupter-later.button', 'Later')}
            </Button>

            <Button emphasis="high" disabled={submitLoading} id="saveProfileButton" type="submit">
              {t('common-ui:save.action', 'Save')}
            </Button>
          </Row>
        </DialogOverlayActions>
      </DialogOverlayFooter>
    </DialogOverlay>
  )
}
